import photo from "../Files/discord server icon.gif"

function RatingCard() {
  return (
    <div className="rating-card">
      <div style={{display:"flex", justifyContent:"center", marginBottom:"15px"}}>
        <img src={photo} width={60} height={60}/>
        <span>Name</span>
      </div>
      <span>Comment</span>
    </div>
  );
}

export default RatingCard;
